class Solution:
    def tictactoe(self, moves):
        rows = [0] * 3
        cols = [0] * 3
        diag = anti = 0
        for idx, (r, c) in enumerate(moves):
            v = 1 if idx % 2 == 0 else -1
            rows[r] += v
            cols[c] += v
            if r == c:
                diag += v
            if r + c == 2:
                anti += v
            if abs(rows[r]) == 3 or abs(cols[c]) == 3 or abs(diag) == 3 or abs(anti) == 3:
                return 'A' if v == 1 else 'B'
        return 'Draw' if len(moves) == 9 else 'Pending'

