var tictactoe = function(moves) {
    const rows = [0,0,0], cols = [0,0,0];
    let diag = 0, anti = 0;
    for (let idx = 0; idx < moves.length; idx++) {
        const [r, c] = moves[idx];
        const v = idx % 2 === 0 ? 1 : -1;
        rows[r] += v; cols[c] += v;
        if (r === c) diag += v;
        if (r + c === 2) anti += v;
        if (Math.abs(rows[r]) === 3 || Math.abs(cols[c]) === 3 ||
            Math.abs(diag) === 3 || Math.abs(anti) === 3) {
            return v === 1 ? 'A' : 'B';
        }
    }
    return moves.length === 9 ? 'Draw' : 'Pending';
};
